"""
Server-side role verification client.
Calls auth-service to verify user roles instead of trusting headers.
"""
import os
import httpx
from typing import List, Optional
import logging

logger = logging.getLogger(__name__)

AUTH_SERVICE_URL = os.environ.get("AUTH_SERVICE_URL", "http://auth-service:9001")
AUTH_SERVICE_FALLBACK = os.environ.get("AUTH_SERVICE_FALLBACK", "http://auth-service.dev-ben.svc.cluster.local:9001")


class AuthClient:
    """Verifies user roles against the auth service (fail-closed)."""

    def __init__(self):
        self._client = httpx.AsyncClient(timeout=5.0)

    async def verify_user_roles(self, token: str) -> dict:
        """
        Call auth service to get verified user info and roles.

        The auth service /api/v1/auth/me response structure:
          {
            "user_id": "...",
            "email": "...",
            "is_superuser": true/false,
            "memberships": [
              {
                "role": {"slug": "admin", "name": "Administrator"},
                "status": "active",
                ...
              }
            ],
            ...
          }

        Returns: {"user_id": str, "email": str, "roles": List[str], "verified": True}
        Raises: PermissionError if auth service is unreachable (fail closed).
        """
        for base_url in [AUTH_SERVICE_URL, AUTH_SERVICE_FALLBACK]:
            try:
                response = await self._client.get(
                    f"{base_url}/api/v1/auth/me",
                    headers={"Authorization": f"Bearer {token}"}
                )
                if response.status_code == 200:
                    data = response.json()

                    # Extract roles from memberships (active memberships only)
                    roles = []
                    for membership in data.get("memberships", []):
                        if membership.get("status") == "active":
                            role = membership.get("role", {})
                            slug = role.get("slug")
                            if slug and slug not in roles:
                                roles.append(slug)

                    # Superuser gets superadmin role
                    if data.get("is_superuser") and "superadmin" not in roles:
                        roles.append("superadmin")

                    return {
                        "user_id": data.get("user_id") or data.get("id") or data.get("sub"),
                        "email": data.get("email", ""),
                        "roles": roles,
                        "verified": True,
                    }
                elif response.status_code == 401:
                    raise PermissionError("Invalid or expired authentication token")
            except httpx.ConnectError:
                logger.warning(f"Auth service unreachable at {base_url}")
                continue
            except PermissionError:
                raise
            except Exception as e:
                logger.error(f"Auth verification failed at {base_url}: {e}")
                continue

        # FAIL CLOSED — if auth service is unreachable, deny the request
        raise PermissionError(
            "Authentication service unavailable - access denied (fail-closed policy)"
        )

    def has_role(self, verified_user: dict, required_role: str) -> bool:
        """Check if verified user has the required role."""
        user_roles = verified_user.get("roles", [])
        # Superadmin always has access
        if "superadmin" in user_roles or "admin" in user_roles:
            return True
        return required_role in user_roles

    def has_any_role(self, verified_user: dict, required_roles: List[str]) -> bool:
        """Check if verified user has any of the required roles."""
        return any(self.has_role(verified_user, role) for role in required_roles)


# Singleton instance
_auth_client: Optional[AuthClient] = None


def get_auth_client() -> AuthClient:
    global _auth_client
    if _auth_client is None:
        _auth_client = AuthClient()
    return _auth_client

